var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다음으로는 최근 화제인 보물에 관한 내용입니다.</color>","JPN":"<color=#ffd34c>次は、最近話題になっている宝物に関する内容です。</color>","ENG":"<color=#ffd34c>Next, we have news on the recent hot topic, the treasure.</color>","TWN":"<color=#ffd34c>接下來是最近熱門的寶箱相關內容。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>주제가 화제에 오른 지 며칠이 지났습니다만 별다른 정보가 없는 탓에 수사는 난항을 겪고 있었죠.</color>","JPN":"<color=#ffd34c>話題になってから数日、特に情報がないため捜査は難航していました。</color>","ENG":"<color=#ffd34c>It has been a few days since the news spread, but there has been no particular progress on the investigation.</color>","TWN":"<color=#ffd34c>熱度已經持續好幾天了，但由於沒有特別的資訊，調查陷入了困境。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>하지만 최근 현장조사팀이 카메라의 복구에 성공했다고 하는데요.</color>","JPN":"<color=#ffd34c>ですがつい先日、現場調査チームがカメラの復元に成功したとの情報が上がっており。</color>","ENG":"<color=#ffd34c>However, we've received reports that the field investigation team has successfully restored the camera.</color>","TWN":"<color=#ffd34c>不過，最近現場調查隊已成功修復攝影鏡頭。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>경찰은 복구된 카메라 영상을 토대로 수사를 재개하겠다는 입장을 밝혔습니다.</color>","JPN":"<color=#ffd34c>警察は復元されたカメラの映像を元に、捜査を再開することを明らかにしました。</color>","ENG":"<color=#ffd34c>The police have revealed that they will continue the investigation based on the footage that has been recovered.</color>","TWN":"<color=#ffd34c>警方表示將根據修復的影片重新展開調查。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음. 웬일로 조금 여유가 생긴 모양이군.","JPN":"うむ。珍しく余裕があるみたいだな。","ENG":"Mm. It seems you have a little more breathing room than usual.","TWN":"嗯，難得有點閒暇時間呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잠깐 숨 돌릴 정도입니다. 쌓인 서류를 치우려면 앞으로 반나절은 걸리겠죠.","JPN":"少し息抜きができる程度です。山積みの書類を片付けるには、半日はかかるでしょう。","ENG":"Just a bit. It'll take several hours to organize the stacked paperwork.","TWN":"只是稍微喘口氣。光是清理堆積的檔案，恐怕就要半天呢。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"유피 양의 동향은 어떻습니까?","JPN":"ユピさんの動向はどうですか？","ENG":"Any updates on Yuppie's whereabouts?","TWN":"悠菲現在怎麼樣了？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이터니움 항법 장치에 의하면 그라운드 원으로 돌아온 모양일세.","JPN":"エタニウム航法装置によると、グラウンド・ワンに戻ってきたようだ。","ENG":"The Eternium navigation system dictates that she is back at Ground One.","TWN":"根據永恆之金導航裝置，她似乎已經回到了G1。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하루만에 대륙을 횡단하다니. 역시 젊음이란 놀랍군!","JPN":"一日で大陸を横断するとは。若さとは驚異的だな！","ENG":"To cross the continent in just one day. Youth is truly an astonishing aspect of life!","TWN":"一天之內橫跨大陸。果然年輕就是令人驚歎啊！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적당히 지치면 미래전략실장도 제 발로 돌아오겠죠. 보험을 들어두길 잘했습니다.","JPN":"疲れれば未来戦略室長も自ら戻ってくるでしょう。保険があって良かったです。","ENG":"The chief of the Future Strategy Department will probably return after tiring herself out. I'm glad we had a backup plan.","TWN":"等我們的室長累了，自然會自己回來的。幸好我提前買了保險。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"요즘 세상에 보물은 무슨.","JPN":"今の世の中に宝物だなんて。","ENG":"Treasure is an absurd ideal in these modern times.","TWN":"現在這個時代，哪裡還有什麼寶藏。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이런, 관심 있어서 보고 있던 게 아니었나?","JPN":"おや、興味があって見ていたわけではないのか？","ENG":"Oh, were you not watching out of interest?","TWN":"哎呀，不是因為感興趣才在看的嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마요. 혹여 일이 커지진 않을까 예의주시하던 참이었습니다.","JPN":"まさか。ひょっとして大事になるんじゃないかと注視していたところです。","ENG":"Of course not. I was watching to make sure things didn't go out of control.","TWN":"怎麼會呢。我一直在密切關注著，只是擔心事情會鬧大而已。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>한편 현장에서는 브라우니 씨가 쥐고 있던 암호문 또한 증거로 남아있었죠.</color>","JPN":"<color=#ffd34c>一方、現場ではブラウニーさんが握っていた暗号文もまた証拠として残っていました。</color>","ENG":"<color=#ffd34c>Meanwhile, Ms. Moore's ciphertext was also left on the scene as evidence.</color>","TWN":"<color=#ffd34c>另一方面，現場還留有布朗尼小姐握著的密碼作為證據。</color>"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>과학수사팀에 의뢰한 결과, 경찰은 해당 암호문의 내용을 다음과 같이 분석하였습니다.</color>","JPN":"<color=#ffd34c>科学捜査チームに依頼した結果、警察はその暗号文の内容を次のように分析しました。</color>","ENG":"<color=#ffd34c>The forensics team has decoded the ciphertext and revealed the following:</color>","TWN":"<color=#ffd34c>委託科學調查組後，警方對該密碼文的內容進行了如下分析。</color>"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"보아라. 날씨 좋은 섬. 귀여운 동물. 시끄러. 외진 곳. 이 몸. 있다.","JPN":"見ろ。天気のいい島。可愛い動物。うるさい。へんぴなところ。私。ある。","ENG":"Witness. Weather is nice. Island Cute animals. Noisy. Isolated location. Move.","TWN":"看哪。天氣真好。小島。可愛的動物。太吵。偏僻的地方。我。這個。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"난잡한 암호로군. 내용을 알아도 장소를 특정하는데 제법 시간이 쓰이겠어.","JPN":"乱雑な暗号だな。内容をわかっていても場所を特定するには結構時間がかかりそうだ。","ENG":"A disorderly cipher. It would take some time to discern the location even after decoding it.","TWN":"真是混亂的密碼。即使知道內容，光定位地點也要花不少時間。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"진지하게 받아들이지 마시죠. 저런 건 전부 사기…","JPN":"真面目に受けないでください。あんなのは全部詐欺……","ENG":"Don't take it too seriously. Those things are all just scams–","TWN":"別太當真。這些全都是騙人的……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":" Hmm?","TWN":"嗯？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 필체와 낙서… 어디선가.","JPN":"あの筆跡と落書き……どこかで。","ENG":"That handwriting and those scribbles... look familiar.","TWN":"這個筆跡和塗鴉……好像在哪裡見過。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그 망할 기술명을 바꾸지 않으면 분명 행군이라고 말했을 텐데.","JPN":"あのクソのような技術名を変えないと、行軍だと言ったはずだ。","ENG":"I made it clear that you'd be marching if you didn't change that damn skill name.","TWN":"我說過了，如果不改掉那個該死的技能名稱，就罰大家去行軍。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"내 말이 말 같지도 않았나 보군. 관리국 완전군장으로 40km 행군… 아니, 수영이다.","JPN":"私の話が耳に入っていなかったようだな。管理局完全軍装で40km行軍……いや、水泳だ。","ENG":"You must've not registered my words at all. You will be marching 40 km in full Administration gear... Actually, you will be swimming.","TWN":"看來你根本沒把我的話當回事。管理局全副武裝行軍40公里……不，用游的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"무인도에 좌표를 찍어둘 테니 내일까지 복귀하도록.","JPN":"無人島に座標を表示しておく。明日までに復帰しろ。","ENG":"I'll set the coordinates to a deserted island, and you are to return by tomorrow.","TWN":"我會在無人島上標記座標，明天之前回來。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"스승님도 너무하시지. 아토믹 힐데 퍼니시먼트가 뭐 어때서?","JPN":"師匠もひどいよね。アトミックヒルデパニッシュメントのなにがいけないの？","ENG":"She's so harsh. What's wrong with Atomic Hilde Punishment?","TWN":"師父也太過分了。希爾德原子懲戒哪裡不好？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"해가 떨어질 것 같으니 방향을 잡기는 힘들 것 같고, 내일까지 섬에서 보내야 하나?","JPN":"日が暮れそうだから方向を把握するのは難しそうだし、明日まで島で生活しないといけないかな。","ENG":"The sun's about to set, so it'll be hard to navigate. I guess I'll have to stay the night on the island.","TWN":"太陽快要下山了，這樣不好認方向，難道要在島上待到明天嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};